export type ReportStatus = 'reported' | 'reviewed' | 'in_progress' | 'resolved';

export interface ReportCategoryData {
  id: string;
  label: string;
  subCategories: { id: string; label: string }[];
}

export type HazardLevel = 'low' | 'medium' | 'high';

export interface Comment {
  id: string;
  text: string;
  author: string;
  timestamp: number;
}

export interface Report {
  id: string;
  lat: number;
  lng: number;
  address?: string;
  mainCategory: string;
  subCategory: string;
  categoryLabel: string; // Gabungan Main - Sub
  description: string;
  photoUrl: string | null;
  afterPhotoUrl?: string | null; // Untuk fitur Before/After
  timestamp: number;
  hazardLevel: HazardLevel;
  status: ReportStatus;
  upvotes: number; // Fitur Verifikasi/Heatmap
  isVerifiedByCurrentUser?: boolean;
  impactMetric?: string; // Contoh: "Membantu 400 pelaju"
  comments?: Comment[];
}

export interface NewReportForm {
  lat: number;
  lng: number;
}

import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { Plus, X, ChevronRight, ChevronLeft, HelpCircle } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

import { Report, HazardLevel, ReportStatus, Comment } from './types';
import { InstructionBox } from './components/InstructionBox';
import { ReportForm } from './components/ReportForm';
import { SearchField } from './components/SearchField';
import { ReportSidebar } from './components/ReportSidebar';
import { MapController } from './components/MapController';
import { OnboardingModal } from './components/OnboardingModal';

// Fix for default Leaflet icons
delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

const createMarkerIcon = (color: string) => new L.Icon({
    iconUrl: `https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-${color}.png`,
    shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png',
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34],
    shadowSize: [41, 41]
});

const icons = {
  reported: createMarkerIcon('grey'),
  reviewed: createMarkerIcon('blue'),
  in_progress: createMarkerIcon('orange'),
  resolved: createMarkerIcon('green'),
  temp: createMarkerIcon('red')
};

const fetchAddressAI = async (lat: number, lng: number): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Apa alamat lengkap dan nama tempat/jalan yang paling mendekati koordinat ini? Berikan jawaban singkat (maksimal 10 kata) yang langsung menunjukkan nama jalan atau lokasi.",
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: lat,
              longitude: lng
            }
          }
        }
      },
    });
    return response.text?.trim() || `${lat.toFixed(4)}, ${lng.toFixed(4)}`;
  } catch (error) {
    console.error("AI Address Fetch Error:", error);
    return `Lokasi: ${lat.toFixed(4)}, ${lng.toFixed(4)}`;
  }
};

const MapEvents = ({ isAddingMode, onMapClick }: { isAddingMode: boolean; onMapClick: (lat: number, lng: number) => void; }) => {
  useMapEvents({
    click(e) {
      if (isAddingMode) {
        onMapClick(e.latlng.lat, e.latlng.lng);
      }
    },
  });
  return null;
};

const App: React.FC = () => {
  const [reports, setReports] = useState<Report[]>([]);
  const [tempLocation, setTempLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  const [isAddingMode, setIsAddingMode] = useState(false);
  const [flyToPosition, setFlyToPosition] = useState<{ lat: number; lng: number } | null>(null);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false); 
  const [showOnboarding, setShowOnboarding] = useState(false);
  const [isPlusHovered, setIsPlusHovered] = useState(false);

  useEffect(() => {
    const hasSeen = localStorage.getItem('hasSeenOnboarding');
    if (!hasSeen) setShowOnboarding(true);
  }, []);

  const handleCloseOnboarding = () => {
    setShowOnboarding(false);
    localStorage.setItem('hasSeenOnboarding', 'true');
  };

  // LOKASI AWAL: BANDUNG ALUN-ALUN
  const bandungCenter: L.LatLngExpression = [-6.9175, 107.6191];
  const bounds = L.latLngBounds(L.latLng(6.0, 95.0), L.latLng(-11.0, 141.0));

  const handleStartAdding = () => {
    setIsAddingMode(true);
    setFlyToPosition(null); 
  };

  const handleMapClick = (lat: number, lng: number) => {
    if (!isAddingMode) return;
    setTempLocation({ lat, lng });
    setIsFormOpen(true);
    setIsAddingMode(false);
  };

  const handleSubmitReport = async (data: {
    mainCategory: string;
    subCategory: string;
    categoryLabel: string;
    description: string;
    photoUrl: string | null;
    hazardLevel: HazardLevel;
  }) => {
    if (!tempLocation) return;

    const tempId = Date.now().toString();
    const newReport: Report = {
      id: tempId,
      lat: tempLocation.lat,
      lng: tempLocation.lng,
      address: 'Menganalisis lokasi...',
      ...data,
      timestamp: Date.now(),
      status: 'reported',
      upvotes: 0,
      comments: [],
    };

    setReports((prev) => [newReport, ...prev]);
    setIsFormOpen(false);
    setTempLocation(null);
    setFlyToPosition({ lat: newReport.lat, lng: newReport.lng });

    const address = await fetchAddressAI(newReport.lat, newReport.lng);
    setReports((prev) => prev.map(r => 
      r.id === tempId ? { ...r, address: address } : r
    ));
  };

  const handleVerifyReport = (id: string) => {
    setReports((prev) => prev.map(r => {
      if (r.id === id) {
        const isVerified = r.isVerifiedByCurrentUser;
        return {
          ...r,
          upvotes: isVerified ? r.upvotes - 1 : r.upvotes + 1,
          isVerifiedByCurrentUser: !isVerified
        };
      }
      return r;
    }));
  };

  const handleStatusChange = (id: string) => {
    const statusCycle: ReportStatus[] = ['reported', 'reviewed', 'in_progress', 'resolved'];
    setReports((prev) => prev.map(r => {
      if (r.id === id) {
        const currentIndex = statusCycle.indexOf(r.status);
        const nextIndex = (currentIndex + 1) % statusCycle.length;
        const newStatus = statusCycle[nextIndex];
        const updates: Partial<Report> = { status: newStatus };
        if (newStatus === 'resolved' && !r.impactMetric) {
           updates.impactMetric = "Masalah terselesaikan dalam 3 hari";
        }
        return { ...r, ...updates };
      }
      return r;
    }));
  };

  const handleAddComment = (reportId: string, text: string) => {
    setReports((prev) => prev.map(r => {
      if (r.id === reportId) {
        const newComment: Comment = {
          id: Date.now().toString(),
          text,
          author: 'Warga',
          timestamp: Date.now()
        };
        return {
          ...r,
          comments: [...(r.comments || []), newComment]
        };
      }
      return r;
    }));
  };

  const handleShareReport = (report: Report) => {
    const dummyLink = `https://lapor-fasilitas.id/report/${report.id}`;
    if (navigator.share) {
      navigator.share({
        title: `Laporan: ${report.categoryLabel}`,
        text: `Bantu verifikasi laporan ini: ${report.description}`,
        url: dummyLink,
      }).catch(console.error);
    } else {
      navigator.clipboard.writeText(dummyLink);
      alert(`Link disalin: ${dummyLink}`);
    }
  };

  const handleSidebarReportClick = (report: Report) => {
    setFlyToPosition({ lat: report.lat, lng: report.lng });
  };

  // Lebar sidebar yang konsisten
  const sidebarWidth = '320px';

  return (
    <div className="h-screen w-full flex overflow-hidden bg-gray-100 font-sans text-gray-800 relative">
      {showOnboarding && <OnboardingModal onClose={handleCloseOnboarding} />}

      {/* Tombol Toggle Sidebar - Diposisikan secara absolut berdasarkan status sidebar */}
      <button
        onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        className="absolute top-1/2 -translate-y-1/2 z-[1005] bg-white hover:bg-gray-50 text-blue-600 p-0 rounded-r-xl shadow-xl border border-gray-200 transition-all duration-300 ease-in-out w-8 h-12 flex items-center justify-center group"
        style={{ left: isSidebarCollapsed ? '0px' : sidebarWidth }}
      >
        {isSidebarCollapsed ? (
          <ChevronRight size={20} strokeWidth={2.5} />
        ) : (
          <ChevronLeft size={20} strokeWidth={2.5} />
        )}
      </button>

      {/* Sidebar Container - Tetap di samping tanpa md: breakpoint */}
      <div 
        className={`h-full flex-shrink-0 bg-white border-r border-gray-200 transition-all duration-300 ease-in-out z-[1001] relative`}
        style={{ width: isSidebarCollapsed ? '0px' : sidebarWidth, opacity: isSidebarCollapsed ? 0 : 1, transform: isSidebarCollapsed ? 'translateX(-100%)' : 'translateX(0)' }}
      >
         <ReportSidebar 
          reports={reports} 
          onReportClick={handleSidebarReportClick} 
          onVerify={handleVerifyReport}
          onShare={handleShareReport}
          onStatusChange={handleStatusChange}
          onAddComment={handleAddComment}
        />
      </div>

      {/* Map Area - flex-1 akan mengambil sisa layar secara otomatis */}
      <div className="flex-1 relative h-full min-w-0">
        <MapContainer 
          center={bandungCenter} 
          zoom={13} 
          minZoom={4}
          maxBounds={bounds}
          maxBoundsViscosity={1.0}
          scrollWheelZoom={true}
          className={`h-full w-full z-0 transition-cursor duration-200 ${isAddingMode ? 'cursor-crosshair' : ''}`}
        >
          <TileLayer
            attribution='&copy; Google Maps'
            url="https://mt1.google.com/vt/lyrs=m&x={x}&y={y}&z={z}"
          />

          <SearchField />
          <MapController targetLocation={flyToPosition} />
          <MapEvents isAddingMode={isAddingMode} onMapClick={handleMapClick} />

          {reports.map((report) => (
            <Marker key={report.id} position={[report.lat, report.lng]} icon={icons[report.status] || icons.reported}>
              <Popup className="custom-popup" autoPan={true}>
                <div className="min-w-[180px] max-w-[220px]">
                  <div className="mb-1 flex justify-between items-center">
                    <span className="inline-block px-1.5 py-0.5 rounded text-[10px] font-bold bg-blue-50 text-blue-600 uppercase tracking-wide">
                      {report.categoryLabel}
                    </span>
                  </div>
                  <h3 className="font-semibold text-gray-900 text-sm mb-1 leading-tight">{report.address}</h3>
                  <p className="text-gray-600 text-xs mb-2 line-clamp-2">{report.description}</p>
                  {report.photoUrl && (
                    <img src={report.photoUrl} alt="Laporan" className="w-full h-24 object-cover rounded-md border border-gray-100 mb-2" />
                  )}
                  <div className="flex justify-between items-center mt-1 pt-1 border-t border-gray-100">
                     <span className="text-[9px] text-gray-400">
                       {new Date(report.timestamp).toLocaleDateString('id-ID')}
                     </span>
                     <span className="text-[10px] font-bold text-blue-600">
                       {report.upvotes} Vote
                     </span>
                  </div>
                </div>
              </Popup>
            </Marker>
          ))}

          {tempLocation && (
            <Marker position={[tempLocation.lat, tempLocation.lng]} icon={icons.temp} />
          )}
        </MapContainer>

        <InstructionBox visible={true} mode={isAddingMode ? 'add' : 'view'} />

        {/* Tombol Bantuan - Selalu terlihat */}
        {!isAddingMode && (
          <div className="fixed bottom-8 left-6 z-[1000] block" style={{ left: isSidebarCollapsed ? '24px' : `calc(${sidebarWidth} + 24px)`, transition: 'left 0.3s ease' }}>
            <button
              onClick={() => setShowOnboarding(true)}
              className="bg-white hover:bg-gray-50 text-gray-800 px-4 py-2 rounded-full shadow-lg border border-gray-200 flex items-center gap-2 transition-all hover:scale-105 active:scale-95 group"
            >
              <HelpCircle size={20} className="text-gray-400 group-hover:text-blue-600" />
              <span className="font-medium text-sm">Bantuan</span>
            </button>
          </div>
        )}

        <div className="absolute bottom-6 right-6 z-[1000] flex flex-col items-end space-y-3">
          {isAddingMode ? (
             <button
              onClick={() => setIsAddingMode(false)}
              className="bg-red-500 hover:bg-red-600 text-white px-6 py-3 rounded-full shadow-lg font-semibold flex items-center transition-all animate-fade-in-up"
            >
              <X size={20} className="mr-2" />
              Batal
            </button>
          ) : (
            <div className="relative">
              <button
                onMouseEnter={() => setIsPlusHovered(true)}
                onMouseLeave={() => setIsPlusHovered(false)}
                onClick={handleStartAdding}
                className="group bg-gradient-to-tr from-blue-600 to-blue-500 hover:from-blue-700 hover:to-blue-600 text-white w-14 h-14 md:w-16 md:h-16 rounded-2xl shadow-xl flex items-center justify-center transition-all hover:scale-110 active:scale-95"
                aria-label="Buat Laporan Baru"
              >
                <Plus size={32} />
              </button>
            </div>
          )}
        </div>

        {isFormOpen && tempLocation && (
          <ReportForm 
            lat={tempLocation.lat} 
            lng={tempLocation.lng} 
            onClose={() => { setIsFormOpen(false); setTempLocation(null); }}
            onSubmit={handleSubmitReport}
          />
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Report, HazardLevel, ReportStatus, Comment } from '../types';
import { Search, MapPin, Share2, ThumbsUp, Clock, Activity, CheckCircle2, Info, MessageCircle, Send, ChevronDown, ChevronUp } from 'lucide-react';

interface ReportSidebarProps {
  reports: Report[];
  onReportClick: (report: Report) => void;
  onVerify: (id: string) => void;
  onShare: (report: Report) => void;
  onStatusChange?: (id: string) => void;
  onAddComment?: (reportId: string, text: string) => void;
}

const getStatusConfig = (status: ReportStatus) => {
  switch (status) {
    case 'reported':
      return { label: 'Dilaporkan', color: 'bg-gray-100 text-gray-600', dot: 'bg-gray-400', icon: Clock };
    case 'reviewed':
      return { label: 'Ditinjau', color: 'bg-blue-100 text-blue-700', dot: 'bg-blue-500', icon: Activity };
    case 'in_progress':
      return { label: 'Dikerjakan', color: 'bg-orange-100 text-orange-700', dot: 'bg-orange-500', icon: Activity };
    case 'resolved':
      return { label: 'Selesai', color: 'bg-green-100 text-green-700', dot: 'bg-green-500', icon: CheckCircle2 };
  }
};

const getHazardInfo = (level: HazardLevel) => {
  switch (level) {
    case 'high': return { bg: 'bg-red-500', text: 'text-white', label: 'Darurat' };
    case 'medium': return { bg: 'bg-yellow-400', text: 'text-yellow-900', label: 'Sedang' };
    case 'low': return { bg: 'bg-green-500', text: 'text-white', label: 'Rendah' };
  }
};

export const ReportSidebar: React.FC<ReportSidebarProps> = ({ reports, onReportClick, onVerify, onShare, onStatusChange, onAddComment }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [hazardFilter, setHazardFilter] = useState<HazardLevel | 'all'>('all');
  const [expandedComments, setExpandedComments] = useState<Record<string, boolean>>({});
  const [commentInputs, setCommentInputs] = useState<Record<string, string>>({});

  const filteredReports = reports.filter((report) => {
    const matchesSearch = 
      report.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
      report.categoryLabel.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (report.address || '').toLowerCase().includes(searchQuery.toLowerCase());

    const matchesHazard = hazardFilter === 'all' || report.hazardLevel === hazardFilter;

    return matchesSearch && matchesHazard;
  });

  const toggleComments = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setExpandedComments(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const handleCommentSubmit = (reportId: string, e: React.FormEvent) => {
    e.preventDefault();
    const text = commentInputs[reportId];
    if (text?.trim() && onAddComment) {
      onAddComment(reportId, text);
      setCommentInputs(prev => ({ ...prev, [reportId]: '' }));
    }
  };

  return (
    <div className="w-full h-full flex flex-col bg-white overflow-hidden">
      {/* Header Sidebar */}
      <div className="px-5 pb-5 pt-6 bg-gradient-to-r from-blue-600 to-indigo-600 z-10 shadow-md flex-shrink-0">
        <h1 className="text-xl font-bold mb-1 tracking-tight text-white">Laporan Warga</h1>
        <p className="text-blue-100 text-[10px] mb-3 opacity-90 uppercase tracking-wider">Pantau fasilitas publik</p>

        <div className="relative group mb-3">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-blue-200 group-focus-within:text-blue-500 transition-colors" size={14} />
          <input
            type="text"
            placeholder="Cari jalan atau masalah..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-8 pr-4 py-2 bg-blue-900/30 border border-blue-400/30 text-white placeholder-blue-200/70 rounded-lg focus:outline-none focus:bg-white focus:text-gray-900 focus:placeholder-gray-400 focus:ring-2 focus:ring-blue-300 transition-all text-xs backdrop-blur-sm"
          />
        </div>

        <div className="flex gap-1.5 overflow-x-auto pb-1 scrollbar-hide">
          {['all', 'high', 'medium', 'low'].map((filter) => (
            <button 
              key={filter}
              onClick={() => setHazardFilter(filter as any)}
              className={`px-2.5 py-1 rounded-full text-[10px] font-bold whitespace-nowrap border transition-all ${
                hazardFilter === filter 
                  ? 'bg-white text-blue-700 border-white shadow-md' 
                  : 'bg-blue-800/40 text-blue-100 border-transparent hover:bg-blue-700/50'
              }`}
            >
              {filter === 'all' ? 'Semua' : filter === 'high' ? 'Darurat' : filter === 'medium' ? 'Sedang' : 'Rendah'}
            </button>
          ))}
        </div>
      </div>

      {/* List Laporan */}
      <div className="flex-1 overflow-y-auto bg-gray-50 p-4 space-y-3">
        {filteredReports.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-gray-400">
            <Info size={32} className="mb-2 opacity-20" />
            <p className="font-medium text-xs">Belum ada laporan</p>
          </div>
        ) : (
          filteredReports.map((report) => {
            const statusInfo = getStatusConfig(report.status);
            const hazardInfo = getHazardInfo(report.hazardLevel);
            const isCommentsExpanded = !!expandedComments[report.id];

            return (
              <div
                key={report.id}
                onClick={() => onReportClick(report)}
                className="bg-white rounded-xl shadow-sm border border-gray-100 hover:shadow-md transition-all cursor-pointer overflow-hidden flex flex-col"
              >
                <div className="p-3">
                  <div className="flex justify-between items-start mb-2">
                    <div className="max-w-[70%]">
                      <h3 className="font-bold text-gray-800 text-xs leading-snug truncate">{report.categoryLabel}</h3>
                      <div className="text-[10px] text-gray-500 flex items-center mt-0.5">
                         <MapPin size={10} className="mr-1 text-gray-400 flex-shrink-0" />
                         <span className="truncate">{report.address}</span>
                      </div>
                    </div>
                    <div className={`px-1.5 py-0.5 rounded text-[9px] font-bold uppercase ${hazardInfo.bg} ${hazardInfo.text}`}>
                      {hazardInfo.label}
                    </div>
                  </div>

                  <div 
                    className="flex items-center gap-1.5 mb-2 bg-gray-50 p-1.5 rounded-lg border border-gray-100 cursor-pointer"
                    onClick={(e) => {
                      e.stopPropagation();
                      if (onStatusChange) onStatusChange(report.id);
                    }}
                  >
                     <div className={`w-1.5 h-1.5 rounded-full ${statusInfo.dot}`}></div>
                     <span className={`text-[10px] font-bold ${statusInfo.color.split(' ')[1]}`}>
                       {statusInfo.label}
                     </span>
                  </div>

                  <p className="text-[11px] text-gray-600 mb-2 line-clamp-2 leading-relaxed">{report.description}</p>

                  <div className="flex items-center justify-between pt-2 border-t border-gray-50">
                    <div className="flex gap-2">
                      <button 
                        onClick={(e) => { e.stopPropagation(); onVerify(report.id); }}
                        className={`flex items-center gap-1 text-[10px] font-bold px-2.5 py-1 rounded-md transition-colors ${report.isVerifiedByCurrentUser ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
                      >
                        <ThumbsUp size={12} className={report.isVerifiedByCurrentUser ? 'fill-blue-700' : ''} />
                        {report.upvotes}
                      </button>

                      <button 
                        onClick={(e) => toggleComments(report.id, e)}
                        className={`flex items-center gap-1 text-[10px] font-bold px-2.5 py-1 rounded-md transition-colors ${isCommentsExpanded ? 'bg-indigo-100 text-indigo-700' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
                      >
                        <MessageCircle size={12} className={isCommentsExpanded ? 'fill-indigo-700' : ''} />
                        {report.comments?.length || 0}
                        {isCommentsExpanded ? <ChevronUp size={10} /> : <ChevronDown size={10} />}
                      </button>
                    </div>

                    <button 
                      onClick={(e) => { e.stopPropagation(); onShare(report); }}
                      className="p-1.5 text-gray-400 hover:text-blue-600 transition-colors"
                    >
                      <Share2 size={14} />
                    </button>
                  </div>
                </div>

                {/* Comment Section (Accordion) */}
                {isCommentsExpanded && (
                  <div 
                    className="bg-gray-50 border-t border-gray-100 p-3 space-y-3 animate-fade-in"
                    onClick={(e) => e.stopPropagation()}
                  >
                    <div className="max-h-32 overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                      {(!report.comments || report.comments.length === 0) ? (
                        <p className="text-[10px] text-gray-400 italic text-center py-2">Belum ada komentar</p>
                      ) : (
                        report.comments.map((comment) => (
                          <div key={comment.id} className="bg-white p-2 rounded-lg shadow-sm border border-gray-100">
                            <div className="flex justify-between items-center mb-1">
                              <span className="text-[9px] font-bold text-blue-600">{comment.author}</span>
                              <span className="text-[8px] text-gray-400">{new Date(comment.timestamp).toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })}</span>
                            </div>
                            <p className="text-[10px] text-gray-700 leading-tight">{comment.text}</p>
                          </div>
                        ))
                      )}
                    </div>

                    {/* Add Comment Input */}
                    <form 
                      onSubmit={(e) => handleCommentSubmit(report.id, e)}
                      className="flex gap-2"
                    >
                      <input 
                        type="text"
                        placeholder="Tulis komentar..."
                        value={commentInputs[report.id] || ''}
                        onChange={(e) => setCommentInputs(prev => ({ ...prev, [report.id]: e.target.value }))}
                        className="flex-1 text-[10px] px-3 py-1.5 rounded-full border border-gray-200 focus:outline-none focus:ring-1 focus:ring-blue-400 bg-white"
                      />
                      <button 
                        type="submit"
                        disabled={!commentInputs[report.id]?.trim()}
                        className="p-1.5 bg-blue-600 text-white rounded-full disabled:bg-gray-300 transition-colors shadow-sm"
                      >
                        <Send size={12} />
                      </button>
                    </form>
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

